What does this program print?

```cpp
#include <iostream>
template <typename T>
struct Tag { static void show() { std::cout << "generic\n"; } };
template <typename T>
struct Tag<T*> { static void show() { std::cout << "pointer\n"; } };
int main() {
    Tag<int>::show();
    Tag<int*>::show();
    Tag<double*>::show();
    Tag<double>::show();
}
```

The programmer wants a partial specialization for `Printer<T*>` but this code does not compile. What is the bug?

```cpp
#include <iostream>
template <typename T>
class Printer {
public:
    static void print(T v) { std::cout << "val: " << v << "\n"; }
};
template <>          // BUG
class Printer<T*> {
public:
    static void print(T* v) { std::cout << "ptr: " << *v << "\n"; }
};
int main() { int x=5; Printer<int*>::print(&x); }
```

